#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[100001], B[100001];
        scanf("%s %s", A, B);
        int Q;
        scanf("%d", &Q);
        while (Q--) {
            int type, x, y;
            scanf("%d %d %d", &type, &x, &y);
            if (type == 1) {
                A[x - 1] = (char)('a' + y - 1);
            } else if (type == 2) {
                B[x - 1] = (char)('a' + y - 1);
            } else {
                int count = 0;
                int charSetA[26] = {0};
                for (int i = x - 1; i < y; i++) {
                    charSetA[A[i] - 'a'] = 1;
                }
                for (int i = 0; i < strlen(B); i++) {
                    int charSetB[26] = {0};
                    for (int j = i; j < strlen(B); j++) {
                        charSetB[B[j] - 'a'] = 1;
                        int match = 1;
                        for (int k = 0; k < 26; k++) {
                            if (charSetA[k] != charSetB[k]) {
                                match = 0;
                                break;
                            }
                        }
                        if (match) {
                            count++;
                        }
                    }
                }
                printf("%d\n", count);
            }
        }
    }
    return 0;
}

