import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String A = sc.next();
            String B = sc.next();
            int Q = sc.nextInt();
            while (Q-- > 0) {
                int type = sc.nextInt();
                int x = sc.nextInt();
                int y = sc.nextInt();
                if (type == 1) {
                    char[] arrA = A.toCharArray();
                    arrA[x - 1] = (char)('a' + y - 1);
                    A = new String(arrA);
                } else if (type == 2) {
                    char[] arrB = B.toCharArray();
                    arrB[x - 1] = (char)('a' + y - 1);
                    B = new String(arrB);
                } else {
                    int count = 0;
                    int[] charSetA = new int[26];
                    for (int i = x - 1; i < y; i++) {
                        charSetA[A.charAt(i) - 'a'] = 1;
                    }
                    for (int i = 0; i < B.length(); i++) {
                        int[] charSetB = new int[26];
                        for (int j = i; j < B.length(); j++) {
                            charSetB[B.charAt(j) - 'a'] = 1;
                            int match = 1;
                            for (int k = 0; k < 26; k++) {
                                if (charSetA[k] != charSetB[k]) {
                                    match = 0;
                                    break;
                                }
                            }
                            if (match) {
                                count++;
                            }
                        }
                    }
                    System.out.println(count);
                }
            }
        }
    }
}

