            A[x - 1] = String.fromCharCode(y + 96);
        } else if (type === 2) {
            B[x - 1] = String.fromCharCode(y + 96);
        } else {
            let count = 0;
            const charSetA = new Array(26).fill(0);
            for (let k = x - 1; k < y; k++) {
                charSetA[A.charCodeAt(k) - 'a'.charCodeAt(0)] = 1;
            }
            for (let k = 0; k < B.length; k++) {
                const charSetB = new Array(26).fill(0);
